```kotlin
fun solve(nums: Array<Long>, k: Long): Long {
    val prefixSums = mutableListOf<Long>()
    var sum = 0L
    for (num in nums) {
        sum += num
        prefixSums.add(sum)
    }

    val modCounts = mutableMapOf<Long, Long>()
    modCounts[0] = 1L

    var minSum = Long.MAX_VALUE

    for (i in prefixSums.indices) {
        val mod = prefixSums[i] % k
        modCounts[mod] = modCounts.getOrDefault(mod, 0L) + 1L

        // Check if there is a previous prefix sum with the same mod
        if (modCounts[mod]!! > 1) {
            minSum = min(minSum, prefixSums[i] - prefixSums[i - 1])
        }
    }

    return minSum
}
