```kotlin
fun solve(nums: Array<Long>, k: Long): Long {
    val prefixSums = mutableListOf<Long>()
    var sum = 0L
    for (num in nums) {
        sum += num
        prefixSums.add(sum)
    }

    val modCounts = mutableMapOf<Long, Long>()
    modCounts[0] = 1L

    var minSum = Long.MAX_VALUE

    for (i in prefixSums.indices) {
        val mod = prefixSums[i] % k
        modCounts[mod] = modCounts.getOrDefault(mod, 0L) + 1L

        // Check if there is a previous prefix sum with the same mod value
        val count = modCounts[mod] ?: 0L
        if (count > 1) {
            minSum = minOf(minSum, prefixSums[i] - prefixSums[i - 1])
        }
    }

    return minSum
}
