```kotlin
fun solve(nums: Array<Long>, k: Long): Long {
    val prefixSums = mutableListOf<Long>()
    var sum = 0L
    for (num in nums) {
        sum += num
        prefixSums.add(sum)
    }

    val modCounts = mutableMapOf<Long, Int>()
    for (i in prefixSums.indices) {
        val mod = prefixSums[i] % k
        modCounts[mod] = modCounts.getOrDefault(mod, 0) + 1
    }

    var minSum = Long.MAX_VALUE
    for (mod in modCounts.keys) {
        if (mod == 0L) {
            minSum = min(minSum, k.toDouble().toLong() * modCounts[mod]!!)
        } else {
            minSum = min(minSum, k.toDouble().toLong() * modCounts[mod]!!)
        }
    }

    return minSum
}
