fun solve(nums: Array<Long>, k: Long): Long {
    val prefixSum = mutableListOf<Long>()
    var sum = 0L
    for (num in nums) {
        sum += num
        prefixSum.add(sum)
    }

    val modMap = mutableMapOf<Long, Int>()
    modMap[0L] = -1
    var minSum = Long.MAX_VALUE

    for (i in prefixSum.indices) {
        val mod = prefixSum[i] % k
        if (modMap.containsKey(mod)) {
            val prevIndex = modMap[mod]!!
            val subArraySum = prefixSum[i] - prefixSum[prevIndex]
            minSum = min(minSum, subArraySum)
        } else {
            modMap[mod] = i
        }
    }

    return minSum
}
